from typing import List, Callable, Optional
import numpy as np

# Snorkel-style labeling function framework

class LabelingFunction:
    """A heuristic rule that assigns a label (or abstains with -1)."""
    def __init__(self, fn: Callable, name: str, label: int):
        self.fn = fn
        self.name = name
        self.label = label

    def apply(self, x) -> int:
        try:
            return self.label if self.fn(x) else -1
        except Exception:
            return -1

# Example labeling functions for sentiment

def contains_positive_emojis(text: str) -> bool:
    return any(c in text for c in ['', '', '[Key]', ''])

def contains_negative_words(text: str) -> bool:
    return any(w in text.lower() for w in ['bad', 'terrible', 'awful', 'hate'])

def review_too_short(text: str) -> bool:
    return len(text.split()) < 3  # Abstain for very short reviews

lfs = [
    LabelingFunction(contains_positive_emojis, 'positive_emoji', 1),
    LabelingFunction(contains_negative_words, 'negative_word', 0),
    LabelingFunction(review_too_short, 'too_short', -1),  # Always abstain
]

# Active learning: uncertainty sampling acquisition function

def uncertainty_sampling(probabilities: np.ndarray, strategy: str = 'least_confident'):
    """Select examples for human labeling."""
    if strategy == 'least_confident':
        # Picks examples where max probability is lowest
        conf = np.max(probabilities, axis=1)
        return np.argsort(conf)
    elif strategy == 'margin':
        # Picks examples where the margin between top-2 classes is smallest
        sorted_probs = np.sort(probabilities, axis=1)[:, ::-1]
        margin = sorted_probs[:, 0] - sorted_probs[:, 1]
        return np.argsort(margin)
    elif strategy == 'entropy':
        # Picks examples with highest entropy (most uncertain)
        entropy = -np.sum(probabilities * np.log(probabilities + 1e-8), axis=1)
        return np.argsort(-entropy)
    return np.arange(len(probabilities))

import numpy as np
from scipy.stats import ks_2samp, chi2_contingency
from typing import Dict, List, Optional

class DriftDetector:
    """Monitor data drift and concept drift for production models.
    ponytail: manual per-feature metric config; auto-tuning thresholds exists.
    """
    def __init__(self, reference_data: Dict[str, np.ndarray]):
        self.reference = reference_data  # {feature_name: values}
        self.alert_history: List[Dict] = []

    def psior(self, expected: np.ndarray, actual: np.ndarray, bins: int = 10) -> float:
        """Population Stability Index."""
        e_perc = np.histogram(expected, bins=bins, range=(0, 1))[0] / len(expected)
        a_perc = np.histogram(actual, bins=bins, range=(0, 1))[0] / len(actual)
        e_perc = np.clip(e_perc, 1e-4, 1.0)
        a_perc = np.clip(a_perc, 1e-4, 1.0)
        return np.sum((a_perc - e_perc) * np.log(a_perc / e_perc))

    def check_data_drift(self, current: Dict[str, np.ndarray]) -> Dict[str, float]:
        """Compute drift score for each feature."""
        drift_scores = {}
        for name in self.reference:
            if name in current:
                if self.reference[name].dtype.kind in ('f', 'i'):
                    # Numeric: Kolmogorov-Smirnov test
                    stat, pval = ks_2samp(self.reference[name], current[name])
                    drift_scores[f'{name}_ks_stat'] = float(stat)
                    drift_scores[f'{name}_ks_pval'] = float(pval)
                    # PSI on binned continuous distribution
                    ref = (self.reference[name] - np.min(self.reference[name])) / (
                        np.ptp(self.reference[name]) + 1e-8
                    )
                    cur = (current[name] - np.min(current[name])) / (
                        np.ptp(current[name]) + 1e-8
                    )
                    drift_scores[f'{name}_psi'] = self.psior(ref, cur)
                else:
                    # Categorical: chi-squared test
                    ref_cat, cur_cat = self.reference[name], current[name]
                    # Use pivot table for chi-square
                    pass  # In production: chi2_contingency
        return drift_scores

    def alert(self, name: str, score: float, threshold: float) -> bool:
        """Consecutive anomaly check: alert only if 3+ windows exceed threshold."""
        self.alert_history.append({'feature': name, 'score': score, 'time': np.random.rand()})
        recent = [a for a in self.alert_history[-5:] if a['feature'] == name]
        return sum(1 for r in recent if r['score'] > threshold) >= 3
